            sub.Text = "DHS SUPORTE";
            sub.Font = new Font("Segoe UI", 8, FontStyle.Regular);
            sub.ForeColor = Color.FromArgb(6, 182, 212);
            sub.Location = new Point(20, 110);
            sub.AutoSize = true;
            leftPanel.Controls.Add(sub);

            // Step indicators
